function pad2(value) {
  return String(value).padStart(2, "0");
}

const now = new Date();

const timeText =
  pad2(now.getHours()) + ":" +
  pad2(now.getMinutes()) + ":" +
  pad2(now.getSeconds());

const dateText =
  pad2(now.getDate()) + "." +
  pad2(now.getMonth() + 1) + "." +
  String(now.getFullYear());

setVar("System.TimeText", timeText);
setVar("System.DateText", dateText);
setVar("System.DateTimeText", timeText + "\n" + dateText);
